## CRDTs — Conflict-Free Replicated Data Types

CRDTs (Shapiro et al., 2011) are data structures that can be replicated across nodes and merged automatically, **always producing a consistent result regardless of the order or concurrency of operations**.

The key insight: if all operations are **monotonically increasing** (they only move in one direction), then merging is just taking the maximum — no coordination, no conflicts, ever.

### Two Flavours of CRDTs

| Type | Full Name | How it works |
|------|-----------|-------------|
| **CvRDT** | Convergent (state-based) | Send full state; merge = join (LUB) |
| **CmRDT** | Commutative (op-based) | Send operations; ops must be commutative |

## G-Counter (Grow-Only Counter)

Each node tracks its own increment count. The global value is the sum of all nodes' counts. Merging takes the max per node — perfectly safe to apply in any order.

```python
from typing import Dict

class GCounter:
    def __init__(self, node_id: str, all_nodes: list):
        self.node_id = node_id
        self.counts: Dict[str, int] = {n: 0 for n in all_nodes}

    def increment(self, amount: int = 1):
        self.counts[self.node_id] += amount

    def value(self) -> int:
        return sum(self.counts.values())

    def merge(self, other: "GCounter") -> "GCounter":
        result = GCounter(self.node_id, list(self.counts.keys()))
        for node in self.counts:
            result.counts[node] = max(self.counts[node], other.counts[node])
        return result

    def __repr__(self):
        return f"GCounter(counts={self.counts}, value={self.value()})"

nodes = ["replica_A", "replica_B", "replica_C"]
ra = GCounter("replica_A", nodes)
rb = GCounter("replica_B", nodes)

# Offline increments
ra.increment(5)   # replica A increments 5 times
rb.increment(3)   # replica B increments 3 times

print(f"Before merge: A={ra.value()}, B={rb.value()}")  # A=5, B=3

merged_at_a = ra.merge(rb)
merged_at_b = rb.merge(ra)

print(f"After merge: A sees {merged_at_a.value()}, B sees {merged_at_b.value()}")
# Both: 8 — correct! 5 + 3 = 8
```

## PN-Counter (Increment/Decrement Counter)

```python
class PNCounter:
    def __init__(self, node_id: str, all_nodes: list):
        self.node_id = node_id
        self.p = GCounter(node_id, all_nodes)  # increments
        self.n = GCounter(node_id, all_nodes)  # decrements

    def increment(self, amount: int = 1):
        self.p.increment(amount)

    def decrement(self, amount: int = 1):
        self.n.increment(amount)

    def value(self) -> int:
        return self.p.value() - self.n.value()

    def merge(self, other: "PNCounter") -> "PNCounter":
        result = PNCounter(self.node_id, list(self.p.counts.keys()))
        result.p = self.p.merge(other.p)
        result.n = self.n.merge(other.n)
        return result

# Example: distributed "likes" counter
pn_a = PNCounter("node_A", ["node_A", "node_B"])
pn_b = PNCounter("node_B", ["node_A", "node_B"])

pn_a.increment(10)  # 10 likes on node A
pn_b.increment(7)   # 7 likes on node B
pn_a.decrement(2)   # 2 unlikes on node A

merged = pn_a.merge(pn_b)
print(f"Total likes: {merged.value()}")  # 15 (10+7-2)
```

## OR-Set (Observed-Remove Set)

Add/remove sets naively conflict (add on A, remove on B concurrently — what wins?). OR-Set uses unique tags per add so removes are precise.

```typescript
type Tag = string;

class ORSet<T> {
  private elements: Map<string, Set<Tag>> = new Map();

  private elementKey(item: T): string {
    return JSON.stringify(item);
  }

  add(item: T, tag: Tag): void {
    const key = this.elementKey(item);
    if (!this.elements.has(key)) this.elements.set(key, new Set());
    this.elements.get(key)!.add(tag);
  }

  remove(item: T): void {
    this.elements.delete(this.elementKey(item));
  }

  has(item: T): boolean {
    const tags = this.elements.get(this.elementKey(item));
    return (tags?.size ?? 0) > 0;
  }

  merge(other: ORSet<T>): ORSet<T> {
    const result = new ORSet<T>();
    const allKeys = new Set([...this.elements.keys(), ...other.elements.keys()]);
    for (const key of allKeys) {
      const tagsA = this.elements.get(key) ?? new Set<Tag>();
      const tagsB = other.elements.get(key) ?? new Set<Tag>();
      const merged = new Set([...tagsA, ...tagsB]);
      if (merged.size > 0) result.elements.set(key, merged);
    }
    return result;
  }
}

const setA = new ORSet<string>();
const setB = new ORSet<string>();
setA.add("apple", "tag-001");  // add on replica A
setB.remove("apple");           // remove on replica B
const merged = setA.merge(setB);
console.log(merged.has("apple")); // true — add wins (surviving tag)
```

